template <bool B>
inline bool VerifyHalValueData(::flatbuffers::VerifierTemplate<B> &verifier, const void *obj, HalValueData type) {
  switch (type) {
    case HalValueData::NONE: {
      return true;
    }
    case HalValueData::bool_val: {
      auto ptr = reinterpret_cast<const audesys::hal::BoolVal *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case HalValueData::s8_val: {
      auto ptr = reinterpret_cast<const audesys::hal::S8Val *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case HalValueData::u8_val: {
      auto ptr = reinterpret_cast<const audesys::hal::U8Val *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case HalValueData::s16_val: {
      auto ptr = reinterpret_cast<const audesys::hal::S16Val *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case HalValueData::u16_val: {
      auto ptr = reinterpret_cast<const audesys::hal::U16Val *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case HalValueData::s32_val: {
      auto ptr = reinterpret_cast<const audesys::hal::S32Val *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case HalValueData::u32_val: {
      auto ptr = reinterpret_cast<const audesys::hal::U32Val *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case HalValueData::s64_val: {
      auto ptr = reinterpret_cast<const audesys::hal::S64Val *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case HalValueData::u64_val: {
      auto ptr = reinterpret_cast<const audesys::hal::U64Val *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case HalValueData::f32_val: {
      auto ptr = reinterpret_cast<const audesys::hal::F32Val *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case HalValueData::f64_val: {
      auto ptr = reinterpret_cast<const audesys::hal::F64Val *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case HalValueData::blob_val: {
      auto ptr = reinterpret_cast<const audesys::hal::BlobVal *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case HalValueData::string_val: {
      auto ptr = reinterpret_cast<const audesys::hal::StringVal *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case HalValueData::array_val: {
      auto ptr = reinterpret_cast<const audesys::hal::ArrayData *>(obj);
      return verifier.VerifyTable(ptr);
    }
    default: return true;
  }
}

template <bool B>
inline bool VerifyHalValueDataVector(::flatbuffers::VerifierTemplate<B> &verifier, const ::flatbuffers::Vector<::flatbuffers::Offset<void>> *values, const ::flatbuffers::Vector<HalValueData> *types) {
  if (!values || !types) return !values && !types;
  if (values->size() != types->size()) return false;
  for (::flatbuffers::uoffset_t i = 0; i < values->size(); ++i) {
    if (!VerifyHalValueData(
        verifier,  values->Get(i), types->GetEnum<HalValueData>(i))) {
      return false;
    }
  }
  return true;
}

